import { wordFrequency, readingTime, sentenceCount, longestWord } from '../src/textAnalysis'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("wordFrequency counts", wordFrequency("the cat and the dog")!.get("the"), 2)
await check("wordFrequency case insensitive", wordFrequency("Hello hello")!.get("hello"), 2)
await check("readingTime 200 words", readingTime(Array(200).fill("word").join(" ")), 1)
await check("readingTime rounds up", readingTime("word", 200), 1)
await check("sentenceCount basic", sentenceCount("Hello. How are you? Fine!"), 3)
await check("sentenceCount empty", sentenceCount(""), 0)
await check("longestWord basic", longestWord("the quick brown fox"), "quick")
await check("longestWord empty", longestWord(""), "")
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
